    async def pause(
        self,
        id: str,
        *,
        behavior: typing.Optional[PauseSubscriptionInputBehavior] = OMIT,
        resumes_at: typing.Optional[dt.datetime] = OMIT,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> SubscriptionPauseResponse:
        """
        Pause an active subscription. While paused:
        - No new invoices are generated
        - The subscription status changes to "paused"
        - The customer retains access until the current period ends (depending on your business logic)

        **Behavior Options:**
        - `keep_as_draft`: Invoices are created as drafts (default)
        - `mark_uncollectible`: Invoices are marked uncollectible
        - `void`: Invoices are voided

        Optionally set `resumes_at` to automatically resume at a future date.

        Parameters
        ----------
        id : str
            Subscription UUID

        behavior : typing.Optional[PauseSubscriptionInputBehavior]
            How to handle invoices during the pause period

        resumes_at : typing.Optional[dt.datetime]
            ISO 8601 date when the subscription should automatically resume. If not provided, subscription stays paused until manually resumed.

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        SubscriptionPauseResponse
            Subscription paused successfully

        Examples
        --------
        import asyncio

        from revkeen import AsyncRevKeen

        client = AsyncRevKeen(
            api_key="YOUR_API_KEY",
        )


        async def main() -> None:
            await client.subscriptions.pause(
                id="id",
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.pause(
            id, behavior=behavior, resumes_at=resumes_at, request_options=request_options
        )
        return _response.data

